```plantuml
@startuml
class CreditAccount {
  ...someAttribute
  applyMonthlyInterest()
  applyMonthlyChange()
  ...someOtherMethod()
}

class DebitAccount {
  ...someAttribute
  applyMonthlyInterest()
  deactivateIfUnderBalanced()
  applyMonthlyChange()
  ...someOtherMethod()
}

class PayrollAccount {
  ...someAttribute
  applyMonthlyChange()
  ...someMethod()
}

class Bank {
  accounts:[Account]
  applyAllMonthlyChanges()
}

interface Account {
  {abstract} applyMonthlyChange()
}

note bottom of Bank
  applyAllMonthlyChanges(){
    ...
    for every account a in accounts{
      a.applyMonthlyChange
    }
  }
end note

CreditAccount ..|> Account
DebitAccount ..|> Account
PayrollAccount ..|> Account
Bank o--> Account

@enduml
```
